			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Species&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 2px 1px; border-style: solid; border-color: rgb(0, 0, 0) rgb(0, 0, 0) rgb(0, 0, 0) rgb(204, 204, 204); border-image: initial; overflow: hidden; vertical-align: bottom; background-color: rgb(183, 183, 183); font-weight: bold;&quot;&gt;Species&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Oxidation state&amp;quot;}&quot; style=&quot;padding: 2px 3px; border-width: 2px 2px 2px 1px; border-style: solid; border-color: rgb(0, 0, 0) rgb(0, 0, 0) rgb(0, 0, 0) rgb(204, 204, 204); border-image: initial; overflow: hidden; vertical-align: bottom; background-color: rgb(183, 183, 183); font-weight: bold; overflow-wrap: break-word;&quot;&gt;Oxidation state&lt;/td&gt;
