			&lt;td style=&quot;border-width: 1px 2px; border-style: solid; border-color: rgb(204, 204, 204) rgb(0, 0, 0) rgb(0, 0, 0); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;KCIO&lt;span style=&quot;position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;&lt;/td&gt;
