			&lt;td style=&quot;border-width: 1px 2px 1px 1px; border-style: solid; border-color: rgb(204, 204, 204) rgb(0, 0, 0) rgb(0, 0, 0) rgb(204, 204, 204); border-image: initial; overflow: hidden; padding: 2px 3px; vertical-align: bottom;&quot;&gt;-1&lt;/td&gt;
